static boolean _isNum(String x){
  try {
    Double.parseDouble(x);
    return true;
  }
 catch (  NumberFormatException e) {
    int radix=10;
    int begin=0;
    int end=x.length();
    int bits=32;
    if (end - begin > 1) {
      char ch=x.charAt(end - 1);
      if ((ch == 'l') || (ch == 'L')) {
        --end;
        bits=64;
      }
      if (end - begin > 1) {
        if (x.charAt(0) == '0') {
          ++begin;
          radix=8;
          if (end - begin > 1) {
            ch=x.charAt(1);
            if ((ch == 'x') || (ch == 'X')) {
              ++begin;
              radix=16;
            }
 else             if ((ch == 'b') || (ch == 'B')) {
              ++begin;
              radix=2;
            }
          }
        }
      }
    }
    try {
      java.math.BigInteger val=new java.math.BigInteger(x.substring(begin,end),radix);
      return (val.bitLength() <= bits);
    }
 catch (    NumberFormatException e2) {
      StringBuilder sb=new StringBuilder();
      for (int idx=begin; idx < end; idx++) {
        char ch=x.charAt(idx);
        if (ch != '_') {
          sb.append(ch);
        }
      }
      try {
        java.math.BigInteger val=new java.math.BigInteger(sb.toString(),radix);
        return (val.bitLength() <= bits);
      }
 catch (      NumberFormatException e3) {
        return false;
      }
    }
  }
}

