private void scrollNodeToVisible(final NodeView node,final int extraWidth){
  if (node == null)   return;
  if (scrollingDirective == ScrollingDirective.DONE || scrollingDirective == ScrollingDirective.ANCHOR) {
    scrollingDirective=ScrollingDirective.MAKE_NODE_VISIBLE;
    showsSelectedAfterScroll=false;
  }
  if (scrolledNode != null && scrollingDirective != ScrollingDirective.MAKE_NODE_VISIBLE) {
    if (node != scrolledNode) {
      if (scrollingDirective == ScrollingDirective.SCROLL_TO_BEST_ROOT_POSITION && !node.isRoot())       scrollingDirective=ScrollingDirective.SCROLL_NODE_TO_CENTER;
      scrollNode(node,scrollingDirective,false);
    }
    return;
  }
  if (!map.isValid()) {
    scrolledNode=node;
    scrollingDirective=ScrollingDirective.MAKE_NODE_VISIBLE;
    this.extraWidth=extraWidth;
    return;
  }
  final int HORIZ_SPACE=10;
  final int HORIZ_SPACE2=20;
  final int VERT_SPACE=5;
  final int VERT_SPACE2=10;
  final JComponent nodeContent=node.getContent();
  int width=nodeContent.getWidth();
  if (extraWidth < 0) {
    width-=extraWidth;
    nodeContent.scrollRectToVisible(new Rectangle(-HORIZ_SPACE + extraWidth,-VERT_SPACE,width + HORIZ_SPACE2,nodeContent.getHeight() + VERT_SPACE2));
  }
 else {
    width+=extraWidth;
    nodeContent.scrollRectToVisible(new Rectangle(-HORIZ_SPACE,-VERT_SPACE,width + HORIZ_SPACE2,nodeContent.getHeight() + VERT_SPACE2));
  }
}

