@Override protected void processElementContent(final String defaultNamespace,final Properties namespaces,final String fullName,final String name,final String prefix) throws IOException, XMLParseException, Exception {
  if (contentCollect != ContentCollect.NONE) {
    boolean inComment=false;
    final TreeXmlReader builder=(TreeXmlReader)getBuilder();
    final StringBuilder contentBuffer=new StringBuilder();
    int level=1;
    int confirmedContentBufferLength=0;
    int closingTagMatchingCharacters=-2;
    for (; ; ) {
      final IXMLReader reader=getReader();
      char ch=reader.read();
      if (inComment) {
        contentBuffer.append(ch);
        if (ch != '-') {
          continue;
        }
        ch=reader.read();
        contentBuffer.append(ch);
        if (ch != '-') {
          continue;
        }
        ch=reader.read();
        contentBuffer.append(ch);
        if (ch != '>') {
          continue;
        }
        inComment=false;
        continue;
      }
      if (ch == '<') {
        ch=reader.read();
        if (ch == '/') {
          if (contentCollect == ContentCollect.BY_CLOSING_TAG_LEVEL) {
            level--;
            if (level == 0) {
              break;
            }
          }
 else {
            confirmedContentBufferLength=contentBuffer.length();
            closingTagMatchingCharacters=-1;
          }
        }
 else         if (contentCollect == ContentCollect.BY_CLOSING_TAG_LEVEL) {
          if (ch == '!') {
            final char read1=reader.read();
            final char read2=reader.read();
            if (read1 != '-' || read2 != '-') {
              throw new XMLParseException(reader.getSystemID(),reader.getLineNr(),"Invalid input: <!" + read1 + read2);
            }
            inComment=true;
            contentBuffer.append("<!--");
            continue;
          }
 else {
            level++;
          }
        }
        contentBuffer.append('<');
      }
 else       if (contentCollect == ContentCollect.BY_CLOSING_TAG_LEVEL && ch == '/') {
        ch=reader.read();
        if (ch == '>') {
          level--;
          if (level == 0) {
            throw new XMLParseException(reader.getSystemID(),reader.getLineNr(),"Invalid input: />");
          }
        }
 else         if (ch == '<') {
          contentBuffer.append('/');
          reader.unread(ch);
          continue;
        }
        contentBuffer.append('/');
      }
      if (contentCollect == ContentCollect.BY_CLOSING_TAG_NAME) {
        if (closingTagMatchingCharacters == -1 || closingTagMatchingCharacters >= 0 && closingTagMatchingCharacters < fullName.length() && fullName.charAt(closingTagMatchingCharacters) == ch) {
          if ((closingTagMatchingCharacters >= 0 && closingTagMatchingCharacters < fullName.length()) || (ch != ' ' && ch != '\t' && ch != '\n'))           closingTagMatchingCharacters++;
        }
 else         if (ch == '>' && closingTagMatchingCharacters == fullName.length()) {
          contentBuffer.setLength(confirmedContentBufferLength);
          closingTagIsReadAndVerified=true;
          break;
        }
 else         closingTagMatchingCharacters=-2;
      }
      contentBuffer.append(ch);
    }
    builder.setElementContent(contentBuffer.toString());
    return;
  }
  super.processElementContent(defaultNamespace,namespaces,fullName,name,prefix);
}

