@ManagedOperation(description="Triggers the retransmission task") public void triggerXmit(){
  SeqnoList missing;
  for (  Map.Entry<Address,ReceiverEntry> entry : recv_table.entrySet()) {
    Address target=entry.getKey();
    ReceiverEntry val=entry.getValue();
    Table<Message> win=val != null ? val.msgs : null;
    if (win != null && val.needToSendAck())     sendAck(target,win.getHighestDeliverable(),val.connId());
    if (win != null && win.getNumMissing() > 0 && (missing=win.getMissing(max_xmit_req_size)) != null) {
      long highest=missing.getLast();
      Long prev_seqno=xmit_task_map.get(target);
      if (prev_seqno == null)       xmit_task_map.put(target,highest);
 else {
        missing.removeHigherThan(prev_seqno);
        if (highest > prev_seqno)         xmit_task_map.put(target,highest);
        if (!missing.isEmpty()) {
          long highest_deliverable=win.getHighestDeliverable(), first=missing.getFirst();
          if (first < highest_deliverable)           missing.removeLowerThan(highest_deliverable + 1);
          retransmit(missing,target);
        }
      }
    }
 else     if (!xmit_task_map.isEmpty())     xmit_task_map.remove(target);
  }
  for (  SenderEntry val : send_table.values()) {
    Table<Message> win=val != null ? val.msgs : null;
    if (win != null) {
      long highest_acked=win.getHighestDelivered();
      long highest_sent=win.getHighestReceived();
      if (highest_acked < highest_sent && val.watermark[0] == highest_acked && val.watermark[1] == highest_sent) {
        Message highest_sent_msg=win.get(highest_sent);
        if (highest_sent_msg != null)         retransmit(highest_sent_msg);
      }
 else       val.watermark(highest_acked,highest_sent);
    }
  }
  if (conn_expiry_timeout > 0)   closeIdleConnections();
  if (conn_close_timeout > 0)   removeExpiredConnections();
}

