public static CommandLineOptions parse(String... args){
  CommandLineParser.CommandLineParserOptions result=new CommandLineParser.CommandLineParserOptions();
  if (args == null || args.length == 0 || !args[0].startsWith("-")) {
    result.setFilesToOpen(args);
    return result;
  }
  int i=0;
  String[] mutableArgs=new String[args.length];
  System.arraycopy(args,0,mutableArgs,0,args.length);
  args=mutableArgs;
  for (; i != args.length; ++i) {
    String arg=args[i];
    if (arg.startsWith("-S")) {
      result.setStopAfterLaunch(true);
      if (arg.length() > 2) {
        args[i]="-" + arg.substring(2);
        --i;
      }
    }
 else     if (arg.startsWith("-N")) {
      result.nonInteractive=true;
      if (arg.length() > 2) {
        args[i]="-" + arg.substring(2);
        --i;
      }
    }
 else     if (arg.startsWith("-X")) {
      if (arg.length() > 2)       result.addMenuItemToExecute(arg.substring(2));
 else       if (args.length > i + 1)       result.addMenuItemToExecute(args[++i]);
    }
 else     if (arg.startsWith("-R")) {
      if (arg.length() > 2)       result.addScriptToExecute(arg.substring(2));
 else       if (args.length > i + 1)       result.addScriptToExecute(args[++i]);
    }
 else     if (arg.startsWith("-U")) {
      String userdir=null;
      if (arg.length() > 2)       userdir=arg.substring(2);
 else       if (args.length > i + 1)       userdir=args[++i];
 else {
        System.err.println("option -U<userdir> misses its parameter");
      }
      if (userdir != null) {
        System.setProperty(Compat.FREEPLANE_USERDIR_PROPERTY,userdir);
        System.setProperty("org.freeplane.old_userfpdir",userdir);
      }
    }
 else     if (arg.startsWith("-h")) {
      result.setHelpRequested(true);
      if (arg.length() > 2) {
        args[i]="-" + arg.substring(2);
        --i;
      }
    }
 else     if (arg.equals("--help")) {
      result.setHelpRequested(true);
    }
 else {
      break;
    }
  }
  for (; i != args.length; ++i)   result.addFilesToOpen(args[i]);
  if (result.isHelpRequested()) {
    System.out.println(result.getHelpMessage());
    System.exit(0);
  }
  return result;
}

