}
IpAddress addr=cache.get(hdr.mbr);
if (addr != null) sendIHaveSockMessage(msg.getSrc(),hdr.mbr,addr);
break;
case FdHeader.I_HAVE_SOCK:
if (hdr.mbr == null || hdr.sock_addr == null) return null;
cache.add(hdr.mbr,hdr.sock_addr);
log.trace("%s: i-have-sock: %s --> %s (cache is %s)",local_addr,hdr.mbr,hdr.sock_addr,cache);
if (hdr.mbr.equals(ping_dest)) ping_addr_promise.setResult(hdr.sock_addr);
break;
