@Override public void run(Context innerContext) throws IOException, InterruptedException {
  setup(innerContext);
  try {
    Configuration conf=innerContext.getConfiguration();
    LinkedList<FetcherThread> fetcherThreads=new LinkedList<>();
    FetchItemQueues fetchQueues=new FetchItemQueues(conf);
    QueueFeeder feeder;
    int threadCount=conf.getInt("fetcher.threads.fetch",10);
    LOG.info("Fetcher: threads: {}",threadCount);
    MimeUtil.setPoolSize(Math.max(10,threadCount / 2));
    int timeoutDivisor=conf.getInt("fetcher.threads.timeout.divisor",2);
    LOG.info("Fetcher: time-out divisor: {}",timeoutDivisor);
    int queueDepthMuliplier=conf.getInt("fetcher.queue.depth.multiplier",50);
    feeder=new QueueFeeder(innerContext,fetchQueues,threadCount * queueDepthMuliplier);
    long timelimit=conf.getLong("fetcher.timelimit",-1);
    if (timelimit != -1)     feeder.setTimeLimit(timelimit);
    feeder.start();
    int startDelay=conf.getInt("fetcher.threads.start.delay",10);
    for (int i=0; i < threadCount; i++) {
      if (startDelay > 0 && i > 0) {
        Thread.sleep(startDelay);
      }
      FetcherThread t=new FetcherThread(conf,getActiveThreads(),fetchQueues,feeder,spinWaiting,lastRequestStart,innerContext,errors,segmentName,parsing,storingContent,pages,bytes);
      fetcherThreads.add(t);
      t.start();
    }
    long timeout=conf.getInt("mapreduce.task.timeout",10 * 60 * 1000) / timeoutDivisor;
    int pagesLastSec;
    int bytesLastSec;
    int throughputThresholdNumRetries=0;
    int throughputThresholdPages=conf.getInt("fetcher.throughput.threshold.pages",-1);
    LOG.info("Fetcher: throughput threshold: {}",throughputThresholdPages);
    int throughputThresholdMaxRetries=conf.getInt("fetcher.throughput.threshold.retries",5);
    LOG.info("Fetcher: throughput threshold retries: {}",throughputThresholdMaxRetries);
    long throughputThresholdTimeLimit=conf.getLong("fetcher.throughput.threshold.check.after",-1);
    int targetBandwidth=conf.getInt("fetcher.bandwidth.target",-1) * 1000;
    int maxNumThreads=conf.getInt("fetcher.maxNum.threads",threadCount);
    if (maxNumThreads < threadCount) {
      LOG.info("fetcher.maxNum.threads can't be < than {} : using {} instead",threadCount,threadCount);
      maxNumThreads=threadCount;
    }
    int bandwidthTargetCheckEveryNSecs=conf.getInt("fetcher.bandwidth.target.check.everyNSecs",30);
    if (bandwidthTargetCheckEveryNSecs < 1) {
      LOG.info("fetcher.bandwidth.target.check.everyNSecs can't be < to 1 : using 1 instead");
      bandwidthTargetCheckEveryNSecs=1;
    }
    int maxThreadsPerQueue=conf.getInt("fetcher.threads.per.queue",1);
    int bandwidthTargetCheckCounter=0;
    long bytesAtLastBWTCheck=0l;
    do {
      pagesLastSec=pages.get();
      bytesLastSec=(int)bytes.get();
      try {
        Thread.sleep(1000);
      }
 catch (      InterruptedException e) {
      }
      pagesLastSec=pages.get() - pagesLastSec;
      bytesLastSec=(int)bytes.get() - bytesLastSec;
      innerContext.getCounter("FetcherStatus","bytes_downloaded").increment(bytesLastSec);
      reportStatus(innerContext,fetchQueues,pagesLastSec,bytesLastSec);
      LOG.info("-activeThreads=" + activeThreads + ", spinWaiting="+ spinWaiting.get()+ ", fetchQueues.totalSize="+ fetchQueues.getTotalSize()+ ", fetchQueues.getQueueCount="+ fetchQueues.getQueueCount());
      if (!feeder.isAlive() && fetchQueues.getTotalSize() < 5) {
        fetchQueues.dump();
      }
      if (throughputThresholdTimeLimit < System.currentTimeMillis() && throughputThresholdPages != -1) {
        if (pagesLastSec < throughputThresholdPages) {
          throughputThresholdNumRetries++;
          LOG.warn("{}: dropping below configured threshold of {} pages per second",throughputThresholdNumRetries,throughputThresholdPages);
          if (throughputThresholdNumRetries == throughputThresholdMaxRetries) {
            LOG.warn("Dropped below threshold too many times, killing!");
            throughputThresholdPages=-1;
            int hitByThrougputThreshold=fetchQueues.emptyQueues();
            if (hitByThrougputThreshold != 0)             innerContext.getCounter("FetcherStatus","hitByThrougputThreshold").increment(hitByThrougputThreshold);
          }
        }
      }
      if (targetBandwidth > 0) {
        if (bandwidthTargetCheckCounter < bandwidthTargetCheckEveryNSecs)         bandwidthTargetCheckCounter++;
 else         if (bandwidthTargetCheckCounter == bandwidthTargetCheckEveryNSecs) {
          long bpsSinceLastCheck=((bytes.get() - bytesAtLastBWTCheck) * 8) / bandwidthTargetCheckEveryNSecs;
          bytesAtLastBWTCheck=bytes.get();
          bandwidthTargetCheckCounter=0;
          int averageBdwPerThread=0;
          if (activeThreads.get() > 0)           averageBdwPerThread=(int)(bpsSinceLastCheck / activeThreads.get());
          LOG.info("averageBdwPerThread : {} kbps",(averageBdwPerThread / 1000));
          if (bpsSinceLastCheck < targetBandwidth && averageBdwPerThread > 0) {
            if ((fetchQueues.getQueueCount() * maxThreadsPerQueue) > activeThreads.get()) {
              long remainingBdw=targetBandwidth - bpsSinceLastCheck;
              int additionalThreads=Math.round(remainingBdw / averageBdwPerThread);
              int availableThreads=maxNumThreads - activeThreads.get();
              additionalThreads=(availableThreads < additionalThreads ? availableThreads : additionalThreads);
              LOG.info("Has space for more threads ({} vs {} kbps) \t=> adding {} new threads",new Object[]{(bpsSinceLastCheck / 1000),(targetBandwidth / 1000),additionalThreads});
              for (int i=0; i < additionalThreads; i++) {
                FetcherThread thread=new FetcherThread(conf,getActiveThreads(),fetchQueues,feeder,spinWaiting,lastRequestStart,innerContext,errors,segmentName,parsing,storingContent,pages,bytes);
                fetcherThreads.add(thread);
                thread.start();
              }
            }
          }
 else           if (bpsSinceLastCheck > targetBandwidth && averageBdwPerThread > 0) {
            long excessBdw=bpsSinceLastCheck - targetBandwidth;
            int excessThreads=Math.round(excessBdw / averageBdwPerThread);
            LOG.info("Exceeding target bandwidth ({} vs {} kbps). \t=> excessThreads = {}",new Object[]{bpsSinceLastCheck / 1000,(targetBandwidth / 1000),excessThreads});
            if (excessThreads >= fetcherThreads.size())             excessThreads=0;
            for (int i=0; i < excessThreads; i++) {
              FetcherThread thread=fetcherThreads.removeLast();
              thread.setHalted(true);
            }
          }
        }
      }
      if (!feeder.isAlive()) {
        int hitByTimeLimit=fetchQueues.checkTimelimit();
        if (hitByTimeLimit != 0)         innerContext.getCounter("FetcherStatus","hitByTimeLimit").increment(hitByTimeLimit);
      }
      if ((System.currentTimeMillis() - lastRequestStart.get()) > timeout) {
        if (LOG.isWarnEnabled()) {
          LOG.warn("Aborting with {} hung threads.",activeThreads);
          for (int i=0; i < fetcherThreads.size(); i++) {
            FetcherThread thread=fetcherThreads.get(i);
            if (thread.isAlive()) {
              LOG.warn("Thread #{} hung while processing {}",i,thread.getReprUrl());
              if (LOG.isDebugEnabled()) {
                StackTraceElement[] stack=thread.getStackTrace();
                StringBuilder sb=new StringBuilder();
                sb.append("Stack of thread #").append(i).append(":\n");
                for (                StackTraceElement s : stack) {
                  sb.append(s.toString()).append('\n');
                }
                LOG.debug(sb.toString());
              }
            }
          }
        }
        return;
      }
    }
 while (activeThreads.get() > 0);
    LOG.info("-activeThreads={}",activeThreads);
  }
  finally {
    cleanup(innerContext);
  }
}
