  }
 else {
    if (opts != null && opts.anycasting())     rpc_stats.addAnycast(false,0,dest_mbrs);
 else     rpc_stats.add(RpcStats.Type.MULTICAST,null,false,0);
  }
  if (opts.anycasting()) {
    boolean first=true;
    for (    Address mbr : dest_mbrs) {
      Message copy=(first ? msg : msg.copy(true,true)).setDest(mbr);
      first=false;
      if (!mbr.equals(local_addr) && copy.isFlagSet(Message.TransientFlag.DONT_LOOPBACK))       copy.clearFlag(Message.TransientFlag.DONT_LOOPBACK);
      down_prot.down(copy);
    }
  }
 else   down_prot.down(msg);
