  JDKToolsLibrary.msg("---- Getting Completed Compound Results ----");
  Map<FullVersion,Iterable<JarJDKToolsLibrary>> completedResults=new TreeMap<FullVersion,Iterable<JarJDKToolsLibrary>>();
  for (  JarJDKToolsLibrary compoundLib : compoundCollapsed) {
    JDKToolsLibrary.msg("compoundLib: " + compoundLib);
    JDKToolsLibrary.msg("    " + compoundLib.location());
    FullVersion compoundVersion=compoundLib.version();
    JarJDKToolsLibrary found=null;
    for (    JarJDKToolsLibrary javaLib : collapsed) {
      if (!javaLib.jdkDescriptor().isBaseForCompound())       continue;
      JDKToolsLibrary.msg("    exact? " + javaLib);
      FullVersion javaVersion=javaLib.version();
      if ((javaVersion.majorVersion().equals(compoundVersion.majorVersion())) && (javaVersion.maintenance() == compoundVersion.maintenance()) && (javaVersion.update() == compoundVersion.update())&& (javaVersion.release() == compoundVersion.release())&& (javaVersion.supports(compoundLib.jdkDescriptor().getMinimumMajorVersion()))) {
        JDKToolsLibrary.msg("        found");
        found=javaLib;
        break;
      }
    }
    if (found == null) {
      for (      JarJDKToolsLibrary javaLib : collapsed) {
        if (!javaLib.jdkDescriptor().isBaseForCompound())         continue;
        JDKToolsLibrary.msg("    major? " + javaLib);
        FullVersion javaVersion=javaLib.version();
        if (javaVersion.majorVersion().equals(compoundVersion.majorVersion()) && javaVersion.supports(compoundLib.jdkDescriptor().getMinimumMajorVersion())) {
          JDKToolsLibrary.msg("        found");
          found=javaLib;
          break;
        }
      }
    }
    if (found != null) {
      JarJDKToolsLibrary lib=makeFromFile(compoundLib.location(),model,compoundLib.jdkDescriptor(),found.bootClassPath());
      if (lib.isValid()) {
        JDKToolsLibrary.msg("    based on version " + lib.version());
        FullVersion v=lib.version();
        if (completedResults.containsKey(v)) {
          completedResults.put(v,IterUtil.compose(lib,completedResults.get(v)));
        }
 else {
          completedResults.put(v,IterUtil.singleton(lib));
        }
      }
    }
  }
  return completedResults;
}

