public static String sgmlUnescape(String s,final Map<String,Character> entities){
  return new StringTranslator(){
    private SGMLState _state=SGMLState.START;
    private final StringBuilder _buffer=new StringBuilder();
    private void reset(){
      _buffer.delete(0,_buffer.length());
      _state=SGMLState.START;
    }
    protected void processChar(    char c){
switch (_state) {
case START:
        if (c == '&') {
          _state=SGMLState.AMP;
          _changed=true;
        }
 else {
          _result.append(c);
        }
      break;
case AMP:
    if (c == '#') {
      _state=SGMLState.NUM;
    }
 else     if (c == ';') {
      throw new IllegalArgumentException("Missing entity name");
    }
 else {
      _state=SGMLState.NAME;
      _buffer.append(c);
    }
  break;
case NAME:
if (c == ';') {
  Character namedChar=entities.get(_buffer.toString());
  if (namedChar == null) {
    throw new IllegalArgumentException("Unrecognized entity name: '" + _buffer.toString() + "'");
  }
 else {
    _result.append((char)namedChar);
    reset();
  }
}
 else {
  _buffer.append(c);
}
break;
case NUM:
if (c == 'x') {
_state=SGMLState.HEX_DIGITS;
}
 else if (isDecimalDigit(c)) {
_state=SGMLState.DEC_DIGITS;
_buffer.append(c);
}
 else {
throw new IllegalArgumentException("Expected decimal digit: '" + c + "'");
}
break;
case HEX_DIGITS:
if (c == ';') {
if (_buffer.length() == 0) {
throw new IllegalArgumentException("Expected hexadecimal digit: ';'");
}
 else {
_result.append((char)Integer.parseInt(_buffer.toString(),16));
reset();
}
}
 else if (isHexDigit(c)) {
_buffer.append(c);
}
 else {
throw new IllegalArgumentException("Expected hexadecimal digit: '" + c + "'");
}
break;
case DEC_DIGITS:
if (c == ';') {
_result.append((char)Integer.parseInt(_buffer.toString()));
reset();
}
 else if (isDecimalDigit(c)) {
_buffer.append(c);
}
 else {
throw new IllegalArgumentException("Expected decimal digit: '" + c + "'");
}
break;
}
}
protected void finish(){
if (_state != SGMLState.START) {
throw new IllegalArgumentException("Unfinished entity");
}
}
