NodeView getNextVisibleSibling(LayoutOrientation requiredLayoutOrientation){
  NodeView sibling=this;
  NodeView lastSibling=this;
  NodeView parentView=getParentView();
  while (sibling != map.getRoot()) {
    lastSibling=sibling;
    LayoutOrientation parentLayoutOrientation=parentView.layoutOrientation();
    if (requiredLayoutOrientation == parentLayoutOrientation) {
      sibling=sibling.getNextSiblingSameParent();
      if (sibling != lastSibling) {
        break;
      }
    }
    sibling=parentView;
    parentView=parentView.getParentView();
  }
  if (sibling.getChildNodesAlignment().isStacked() && !sibling.usesHorizontalLayout())   return sibling;
  while (sibling.getModel().getNodeLevel(map.getFilter()) < map.getSiblingMaxLevel() && sibling.layoutOrientation() == requiredLayoutOrientation) {
    final NodeView first=sibling.getFirst(sibling.isRoot() ? lastSibling : null,this.isTopOrLeft(),!this.isTopOrLeft());
    if (first == null) {
      break;
    }
    sibling=first;
  }
  if (sibling.isRoot()) {
    return this;
  }
  return sibling;
}

