      }
    }
  }
 catch (  Exception e) {
    rootCause=e;
  }
 finally {
    if (null != sink) {
      try {
        sink.close(reporter);
      }
 catch (      Exception e) {
        if (null == rootCause) {
          rootCause=e;
        }
 else {
          LOG.error("Swallowing exception on close of " + outputFileName,e);
        }
      }
    }
    if (null != rootCause) {
      if (rootCause instanceof RuntimeException) {
        throw (RuntimeException)rootCause;
      }
      if (rootCause instanceof IOException) {
