 else {
        if (resumeIfFailed)         up(new Event(Event.RESUME,new ArrayList<>(new_view.getMembers())));
        log.warn("%s: GMS flush by coordinator failed",local_addr);
      }
    }
    return successfulFlush;
  }
 catch (  Exception e) {
    return false;
  }
}

