private void developAlignment(final Alignment ali){
  System.out.format("developAlignment(term=%s, text=%s, r=%d, c=%d)",ali.searchTermString,ali.searchTextString,ali.r,ali.c);
  if (ali.r == 0 && ali.c == 0) {
    alignmentsDone.add(ali);
    System.out.println();
    ali.print();
  }
 else {
    if (ali.r >= 1 && ali.c >= 1 && matrix[ali.r][ali.c] == matrix[ali.r - 1][ali.c - 1] + (isMatch(ali.r,ali.c) ? 0 : costMismatch)) {
      System.out.format("=> match/mismatch\n");
      alignmentsInProgress.push(new Alignment(searchTerm.charAt(ali.r - 1) + ali.searchTermString,searchText.charAt(ali.c - 1) + ali.searchTextString,ali.prob,ali.matchStart,ali.matchEnd,ali.r - 1,ali.c - 1));
    }
    if (type == Type.SemiGlobal && ali.r == 0) {
      System.out.format("=> insertions at beginning\n");
      int c=ali.c, matchStart=ali.matchStart;
      StringBuilder searchTermPrefix=new StringBuilder();
      StringBuilder searchTextPrefix=new StringBuilder();
      while (c > 0) {
        searchTermPrefix.append('-');
        searchTextPrefix.insert(0,searchText.charAt(c - 1));
        matchStart+=1;
        c--;
      }
      alignmentsInProgress.push(new Alignment(searchTermPrefix.toString() + ali.searchTermString,searchTextPrefix.toString() + ali.searchTextString,ali.prob,matchStart,ali.matchEnd,0,0));
    }
    if (ali.c >= 1 && matrix[ali.r][ali.c] == matrix[ali.r][ali.c - 1] + costIndel) {
      System.out.format("=> insertion\n");
      alignmentsInProgress.push(new Alignment("-" + ali.searchTermString,searchText.charAt(ali.c - 1) + ali.searchTextString,ali.prob,ali.matchStart,ali.matchEnd,ali.r,ali.c - 1));
    }
    if (ali.r >= 1 && matrix[ali.r][ali.c] == matrix[ali.r - 1][ali.c] + costIndel) {
      System.out.format("=> deletion\n");
      alignmentsInProgress.push(new Alignment(searchTerm.charAt(ali.r - 1) + ali.searchTermString,"-" + ali.searchTextString,ali.prob,ali.matchStart,ali.matchEnd,ali.r - 1,ali.c));
    }
    if (ali.r >= 2 && ali.c >= 2 && matrix[ali.r][ali.c] == matrix[ali.r - 2][ali.c - 2] + costTranspos && searchTerm.charAt(ali.r - 2) == searchText.charAt(ali.c - 1) && searchTerm.charAt(ali.r - 1) == searchText.charAt(ali.c - 2)) {
      System.out.format("=> transposition\n");
      alignmentsInProgress.push(new Alignment(searchTerm.substring(ali.r - 2,ali.r) + ali.searchTermString,searchText.substring(ali.c - 2,ali.c) + ali.searchTextString,ali.prob,ali.matchStart,ali.matchEnd,ali.r - 2,ali.c - 2));
    }
  }
}

